-- 00108_import_djep_email_templates.sql
-- Imports 132 DJEP automation templates (107 email + 25 SMS) into email_templates.
-- All imported disabled (schedule_enabled=false); blank subjects; review flags on unmapped anchors/statuses.
-- Idempotent: upserts on legacy_djep_id, never touches hand-built XOS templates (legacy_djep_id is null).

alter table email_templates add column if not exists legacy_djep_id bigint;
alter table email_templates add column if not exists is_sms boolean not null default false;
alter table email_templates add column if not exists djep_was_enabled boolean not null default false;
alter table email_templates add column if not exists review_reasons text[] not null default '{}';
do $$ begin
  if not exists (select 1 from pg_constraint where conname = 'email_templates_legacy_djep_id_key') then
    alter table email_templates add constraint email_templates_legacy_djep_id_key unique (legacy_djep_id);
  end if;
end $$;

insert into email_templates
  (legacy_djep_id, name, display_name, group_name, subject, body_html, is_active, is_sms, djep_was_enabled,
   schedule_enabled, schedule_days, schedule_direction, schedule_anchor,
   sched_status_ids, sched_event_type_ids, schedule_from, sched_send_to, review_reasons)
select
  legacy_djep_id, name, display_name, group_name, subject, body_html, is_active, is_sms, djep_was_enabled,
  schedule_enabled, schedule_days, schedule_direction, schedule_anchor,
  sched_status_ids::uuid[], sched_event_type_ids::uuid[], schedule_from, sched_send_to, review_reasons
from jsonb_to_recordset($DJEP_2026$[{"legacy_djep_id":216841,"name":"Post Event Thank You","display_name":"Post Event Thank You","group_name":"GENERAL","subject":"","body_html":"<first_name>:\r\n\r\nWe just wanted to drop a short note thanking you for letting us be a part of the event on <event_date_medium>.  It's our hopes that <djemployee_name> was able to do a great job for you and that everyone enjoyed themselves.\r\n\r\nWe welcome your comments and feedback.  We also look forward to the opportunity of working with you or someone you've kindly referred us to sometime in the future.\r\n\r\nThank you again,\r\n<company_contact>\r\n<company_name>\r\n<company_telephone>","is_active":true,"is_sms":false,"djep_was_enabled":false,"schedule_enabled":false,"schedule_days":0,"schedule_direction":"before","schedule_anchor":"event_date","sched_status_ids":[],"sched_event_type_ids":[],"schedule_from":"company","sched_send_to":["primary_client"],"review_reasons":[]},{"legacy_djep_id":217287,"name":"Day 1 - Quote Sent","display_name":"Day 1 - Quote Sent","group_name":"QUOTE SENT AUTOMATION","subject":"","body_html":"Hey <first_name>, I just sent over the quote you requested!\r\n\r\nLet me know if you have any questions or need any adjustments—I’m happy to help!","is_active":true,"is_sms":true,"djep_was_enabled":false,"schedule_enabled":false,"schedule_days":1,"schedule_direction":"after","schedule_anchor":"event_date","sched_status_ids":[],"sched_event_type_ids":[],"schedule_from":"company","sched_send_to":["primary_client"],"review_reasons":["Imported timing anchor “Custom Event Date 2” has no XOS equivalent — pick a send trigger before enabling."]},{"legacy_djep_id":217289,"name":"Day 3 - Follow up TXT","display_name":"Day 3 - Follow up TXT","group_name":"QUOTE SENT AUTOMATION","subject":"","body_html":"Hey! I just wanted to follow up and see how you're doing. Have you had a chance to go over the quote yet? \r\n\r\n- <salesperson_first_name>, Xpress Entertainment","is_active":true,"is_sms":true,"djep_was_enabled":true,"schedule_enabled":false,"schedule_days":3,"schedule_direction":"after","schedule_anchor":"event_date","sched_status_ids":["a33c790f-b534-4024-ad09-cc36368dd0ac"],"sched_event_type_ids":[],"schedule_from":"company","sched_send_to":["primary_client"],"review_reasons":["Imported timing anchor “Custom Event Date 2” has no XOS equivalent — pick a send trigger before enabling."]},{"legacy_djep_id":217291,"name":"Active Lead 1","display_name":"Active Lead 1","group_name":"ACTIVE LEADS","subject":"","body_html":"Hi! This is Drew from Xpress Entertainment.\r\nThanks for reaching out about entertainment for your <event_type>!\r\nGood news — we’re available on <event_date_short>!\r\nWhen’s a good time to connect and go over the details?","is_active":true,"is_sms":true,"djep_was_enabled":false,"schedule_enabled":false,"schedule_days":1,"schedule_direction":"after","schedule_anchor":"event_date","sched_status_ids":["60be24e8-cf5a-46fc-95b7-15090fd1b2fc"],"sched_event_type_ids":[],"schedule_from":"master_admin","sched_send_to":["primary_client"],"review_reasons":["Imported timing anchor “Custom Event Date 3” has no XOS equivalent — pick a send trigger before enabling."]},{"legacy_djep_id":217292,"name":"Xpress DJs Booking Contract","display_name":"0 - Booking Agreement","group_name":"BOOKING AGREEMENT","subject":"","body_html":"<!DOCTYPE html>\r\n<html lang=\"en\" xmlns:o=\"urn:schemas-microsoft-com:office:office\" xmlns:v=\"urn:schemas-microsoft-com:vml\">\r\n<head>\r\n\t<title></title>\r\n\t<meta http-equiv=\"Content-Type\" content=\"text/html; charset=utf-8\"><meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\"><!--[if mso]><xml><o:OfficeDocumentSettings><o:PixelsPerInch>96</o:PixelsPerInch><o:AllowPNG/></o:OfficeDocumentSettings></xml><![endif]--><!--[if !mso]><!-->\r\n\t<link href=\"https://fonts.googleapis.com/css?family=Roboto\" rel=\"stylesheet\" type=\"text/css\" />\r\n\t<link href=\"https://fonts.googleapis.com/css?family=Open+Sans\" rel=\"stylesheet\" type=\"text/css\" /><!--<![endif]-->\r\n\t<style type=\"text/css\">* {\r\n\t\t\tbox-sizing: border-box;\r\n\t\t}\r\n\r\n\t\tbody {\r\n\t\t\tmargin: 0;\r\n\t\t\tpadding: 0;\r\n\t\t}\r\n\r\n\t\ta[x-apple-data-detectors] {\r\n\t\t\tcolor: inherit !important;\r\n\t\t\ttext-decoration: inherit !important;\r\n\t\t}\r\n\r\n\t\t#MessageViewBody a {\r\n\t\t\tcolor: inherit;\r\n\t\t\ttext-decoration: none;\r\n\t\t}\r\n\r\n\t\tp {\r\n\t\t\tline-height: inherit\r\n\t\t}\r","is_active":true,"is_sms":false,"djep_was_enabled":false,"schedule_enabled":false,"schedule_days":0,"schedule_direction":"before","schedule_anchor":"event_date","sched_status_ids":[],"sched_event_type_ids":[],"schedule_from":"master_admin","sched_send_to":["primary_client"],"review_reasons":[]},{"legacy_djep_id":217293,"name":"Contract Received - Next Step","display_name":"Contract Signed","group_name":"GENERAL","subject":"","body_html":"Hi <first_name>,\r\n\r\nThis is notification that we have received your signed contract. A copy of the contract was emailed to you separately. \r\n\r\nNEXT STEP:\r\nPlease make your <retainer_fee> deposit payment to fully complete your booking. We offer two forms of payment. I am able to send you an invoice through square to pay with Credit/Debit card or For a Fee-Free payment method you may also Zelle us to \"Office@XpressDJs.com\", Please include your name and event date in the description. \r\n\r\nif you'd like an invoice please let me know and we will get that right over to you.\r\n\r\nDEPOSIT AMOUNT DUE: <retainer_fee>\r\n\r\nPlease let me know should you have any other questions\r\n\r\nThanks, \r\n\r\nDarlene Fisher\r\nOffice Manager\r\n954-233-0698","is_active":true,"is_sms":false,"djep_was_enabled":false,"schedule_enabled":false,"schedule_days":0,"schedule_direction":"after","schedule_anchor":"event_date","sched_status_ids":[],"sched_event_type_ids":[],"schedule_from":"master_admin","sched_send_to":["primary_client"],"review_reasons":[]},{"legacy_djep_id":217294,"name":"Follow-up on Your Event Quote from Xpress Entertainment","display_name":"Quote Sent - Reminder 1","group_name":"QUOTE","subject":"","body_html":"<html>\r\n<head>\r\n\t<title></title>\r\n</head>\r\n<body data-gr-ext-installed=\"\" data-new-gr-c-s-check-loaded=\"14.1121.0\">\r\n<p>Hey <first_name>,<br />\r\n\t<br />\r\n\tI hope this email finds you well. I wanted to follow up on the quote we sent you two days ago for your upcoming <event_type>. We understand that <event_type> planning requires careful consideration, and we wanted to ensure that all your questions were answered and that you have all the information you need to make an informed decision.&nbsp;<br />\r\n\t<br />\r\n\tIf you have any further questions or require additional details regarding the quote, please don&#39;t hesitate to reach out. We would be more than happy to provide any clarifications or modifications to meet your specific requirements. Our goal is to ensure that every aspect of your event aligns perfectly with your vision and exceeds your expectations.<br />\r\n\t<br />\r\n\tWe genuinely value your interest in our services and appreciate the opportunity to be a part of your event. Your","is_active":true,"is_sms":false,"djep_was_enabled":true,"schedule_enabled":false,"schedule_days":2,"schedule_direction":"after","schedule_anchor":"event_date","sched_status_ids":["a68a9f16-ae52-4442-941a-cc7b9ceed711"],"sched_event_type_ids":[],"schedule_from":"salesperson","sched_send_to":["primary_client","salesperson"],"review_reasons":["Imported timing anchor “Custom Event Date 2” has no XOS equivalent — pick a send trigger before enabling."]},{"legacy_djep_id":217295,"name":"Your Payment Reminder - Xpress DJs","display_name":"Payment Reminder - Payment 2","group_name":"PAYMENTS","subject":"","body_html":"Hello <first_name>, \r\n\r\nThis is a friendly reminder that your second payment to Xpress DJs of <payment_2_amount> is due tomorrow, <payment_2_date>. \r\nPlease visit our website at www.xpressdjs.com/payments to make your payment. \r\n\r\nHere are the details of your account:\r\n\r\nTOTAL COST OF SERVICES: <total_fee>\r\nDEPOSIT: <retainer_fee>\r\n\r\nTOTAL PAYMENTS DUE: <total_minus_payments>\r\n\r\nIf you've already made your payment please ignore this email\r\nLet me know if you have any questions!\r\n\r\nThank you,\r\n\r\nDarlene Fisher\r\nOffice Manager\r\noffice@XpressDJs.com\r\n954-233-0698\r\n","is_active":true,"is_sms":false,"djep_was_enabled":false,"schedule_enabled":false,"schedule_days":1,"schedule_direction":"before","schedule_anchor":"event_date","sched_status_ids":["c0d3e855-ac0c-4a14-afdf-c00f7b5dbec5"],"sched_event_type_ids":[],"schedule_from":"master_admin","sched_send_to":["primary_client","master_admin"],"review_reasons":["Imported timing anchor “Scheduled Payment #2” has no XOS equivalent — pick a send trigger before enabling."]},{"legacy_djep_id":217296,"name":"Payment 2 Reminder","display_name":"Payment 2 Reminder","group_name":"PAYMENT REMINDERS","subject":"","body_html":"Hey <first_name>, \r\n\r\nThis is Darlene from Xpress Entertainment, just wanted to give you a friendly reminder that your second payment is due tomorrow in the amount of <second_payment_amount>. Please check your email for instructions on how to make your payment. Thank you!","is_active":true,"is_sms":true,"djep_was_enabled":true,"schedule_enabled":false,"schedule_days":1,"schedule_direction":"before","schedule_anchor":"event_date","sched_status_ids":["c0d3e855-ac0c-4a14-afdf-c00f7b5dbec5"],"sched_event_type_ids":[],"schedule_from":"master_admin","sched_send_to":["primary_client"],"review_reasons":["Imported timing anchor “Scheduled Payment #2” has no XOS equivalent — pick a send trigger before enabling."]},{"legacy_djep_id":217297,"name":"Payment 3 Reminder","display_name":"Payment 3 Reminder","group_name":"PAYMENT REMINDERS","subject":"","body_html":"Hi <first_name>!\r\n\r\nJust wanted to give you a friendly reminder that your third payment is due tomorrow in the amount of <second_payment_amount>. Please check your email for instructions on how to make your payment. Thank you! let me know if you have any questions. :)","is_active":true,"is_sms":true,"djep_was_enabled":true,"schedule_enabled":false,"schedule_days":1,"schedule_direction":"before","schedule_anchor":"event_date","sched_status_ids":["c0d3e855-ac0c-4a14-afdf-c00f7b5dbec5"],"sched_event_type_ids":[],"schedule_from":"company","sched_send_to":[],"review_reasons":["Imported timing anchor “Scheduled Payment #3” has no XOS equivalent — pick a send trigger before enabling."]},{"legacy_djep_id":217298,"name":"Booking Agreement Notification","display_name":"Booking Agreement Notification","group_name":"CONTRACT","subject":"","body_html":"Xpress Entertainment:\r\n\r\nWe are so excited to celebrate with you on <event_date_short>! we just sent over our booking agreement, please let us know if you have any questions. You might have to check spam, Thank you!","is_active":true,"is_sms":true,"djep_was_enabled":false,"schedule_enabled":false,"schedule_days":0,"schedule_direction":"after","schedule_anchor":"contract_sent_date","sched_status_ids":["c0c9d5e3-2703-4a33-8c71-90c43d228249"],"sched_event_type_ids":[],"schedule_from":"company","sched_send_to":[],"review_reasons":[]},{"legacy_djep_id":217299,"name":"Create Wedding Ceremony & Reception in Vibo","display_name":"Create Vibo Account - Weddings (gs779a2a)","group_name":"ZAPIER","subject":"","body_html":"Event Name: <event_name>\r\nEvent Type: <event_type>\r\nEvent Date: <event_date>\r\nEvent Start Time: <start_time>\r\nEvent End Time: <end_time>\r\nEvent Set-up Time: <start_time>\r\nEvent Location: <event_location> - <event_location_address>, <event_location_city>,<event_location_state>\r\n\r\nContact 1 First Name: <first_name>\r\nContact 1 Last Name: <last_name>\r\nContact 1 Email Address: <email>\r\nContact 1 Cell Phone Number: <cell_phone>","is_active":true,"is_sms":false,"djep_was_enabled":false,"schedule_enabled":false,"schedule_days":0,"schedule_direction":"before","schedule_anchor":"event_date","sched_status_ids":[],"sched_event_type_ids":[],"schedule_from":"master_admin","sched_send_to":["primary_client"],"review_reasons":[]},{"legacy_djep_id":217301,"name":"Your Payment Reminder - Xpress DJs","display_name":"Third Payment Reminder","group_name":"PAYMENTS","subject":"","body_html":"Hello <first_name>, \r\n\r\nThis is a friendly reminder that your third payment to Xpress DJs of <payment_3_amount> is due tomorrow, <payment_3_date>. \r\nPlease visit our website at www.xpressdjs.com/payments to make your payment. \r\n\r\nHere are the details of your account:\r\n\r\nTOTAL COST OF SERVICES: <total_fee>\r\nDEPOSIT: <retainer_fee>\r\n\r\nTOTAL PAYMENTS DUE: <total_minus_payments>\r\n\r\nPlease let me know if you have any questions!\r\n\r\nThank you,\r\n\r\nDarlene Fisher\r\nOffice Manager\r\noffice@XpressDJs.com\r\n954-233-0698\r\n","is_active":true,"is_sms":false,"djep_was_enabled":false,"schedule_enabled":false,"schedule_days":1,"schedule_direction":"before","schedule_anchor":"event_date","sched_status_ids":["c0d3e855-ac0c-4a14-afdf-c00f7b5dbec5"],"sched_event_type_ids":[],"schedule_from":"master_admin","sched_send_to":["primary_client"],"review_reasons":["Imported timing anchor “Scheduled Payment #3” has no XOS equivalent — pick a send trigger before enabling."]},{"legacy_djep_id":217302,"name":"Xpress DJs Receipt","display_name":"Client Receipt Email","group_name":"GENERAL","subject":"","body_html":"<html>\r\n<head>\r\n\t<title></title>\r\n</head>\r\n<body data-gr-ext-installed=\"\" data-new-gr-c-s-check-loaded=\"14.1068.0\">Hello <first_name>,<br />\r\n<br />\r\nThank you for your recent payment towards your event on&nbsp;<event_date>.&nbsp;<br />\r\n<br />\r\nPlease see your receipt attached to this email.<br />\r\n<br />\r\nThank you,&nbsp;<br />\r\n<br />\r\nDarlene Fisher<br />\r\nOffice Manager<br />\r\nOffice@Xressdjs.com<br />\r\n954-233-0698</body>\r\n</html>\r\n","is_active":true,"is_sms":false,"djep_was_enabled":false,"schedule_enabled":false,"schedule_days":0,"schedule_direction":"before","schedule_anchor":"event_date","sched_status_ids":[],"sched_event_type_ids":[],"schedule_from":"master_admin","sched_send_to":["primary_client"],"review_reasons":[]},{"legacy_djep_id":217303,"name":"Your Xpress Entertainment Proposal is ready to view!","display_name":"Proposal Email","group_name":"QUOTE","subject":"","body_html":"<!DOCTYPE html>\r\n<html lang=\"en\" xmlns:o=\"urn:schemas-microsoft-com:office:office\" xmlns:v=\"urn:schemas-microsoft-com:vml\">\r\n<head>\r\n\t<title></title>\r\n\t<meta http-equiv=\"Content-Type\" content=\"text/html; charset=utf-8\"><meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\"><!--[if mso]><xml><o:OfficeDocumentSettings><o:PixelsPerInch>96</o:PixelsPerInch><o:AllowPNG/></o:OfficeDocumentSettings></xml><![endif]--><!--[if !mso]><!-->\r\n\t<link href=\"https://fonts.googleapis.com/css?family=Montserrat\" rel=\"stylesheet\" type=\"text/css\" /><!--<![endif]-->\r\n\t<style type=\"text/css\">* {\r\n\t\t\tbox-sizing: border-box;\r\n\t\t}\r\n\r\n\t\tbody {\r\n\t\t\tmargin: 0;\r\n\t\t\tpadding: 0;\r\n\t\t}\r\n\r\n\t\ta[x-apple-data-detectors] {\r\n\t\t\tcolor: inherit !important;\r\n\t\t\ttext-decoration: inherit !important;\r\n\t\t}\r\n\r\n\t\t#MessageViewBody a {\r\n\t\t\tcolor: inherit;\r\n\t\t\ttext-decoration: none;\r\n\t\t}\r\n\r\n\t\tp {\r\n\t\t\tline-height: inherit\r\n\t\t}\r\n\r\n\t\t.desktop_hide,\r\n\t\t.desktop_hide table {\r\n\t\t\tmso-hide: all;\r\n\t\t\tdisplay: none;\r\n\t\t\tmax-height","is_active":true,"is_sms":false,"djep_was_enabled":false,"schedule_enabled":false,"schedule_days":0,"schedule_direction":"before","schedule_anchor":"event_date","sched_status_ids":[],"sched_event_type_ids":[],"schedule_from":"master_admin","sched_send_to":["primary_client"],"review_reasons":[]},{"legacy_djep_id":217305,"name":"You're Almost Booked!","display_name":"DJ Booking Notification","group_name":"EMPLOYEES","subject":"","body_html":"<html>\r\n<head>\r\n\t<title></title>\r\n</head>\r\n<body data-gr-ext-installed=\"\" data-new-gr-c-s-check-loaded=\"14.1117.0\">\r\n<p>Hey Party Pro!<br />\r\n\t<br />\r\n\tYou&#39;re (almost) BOOKED! Congrats! I just sent out a contract for the date below and 99% of the time that means it&#39;s happening!<br />\r\n\t<br />\r\n\t<span style=\"font-size:18px;\"><strong>EVENT INFORMATION:</strong></span><br />\r\n\t<br />\r\n\t<strong>Contact Name:&nbsp;</strong><first_name>&nbsp;<last_name><br />\r\n\t<strong>Contact Phone:</strong>&nbsp;<cell_phone>&nbsp;<strong>(ONLY FOR DJ USE)</strong><br />\r\n\t<strong>Event Date:</strong> <event_date><br />\r\n\t<strong>Event Type:</strong> <event_type><br />\r\n\t<strong>Set-up Time:&nbsp;</strong><setup_time><br />\r\n\t<strong>Start Time: </strong><start_time><br />\r\n\t<strong>End Time:</strong> <end_time><br />\r\n\t<strong>Booking Notes: </strong><comments><br />\r\n\t<br />\r\n\t<strong>\r\n\t<span style=\"font-size:18px;\">VENUE INFORMATION:</span></strong><br />\r\n\t<br />\r\n\t<strong>Event Location:</stro","is_active":true,"is_sms":false,"djep_was_enabled":false,"schedule_enabled":false,"schedule_days":0,"schedule_direction":"before","schedule_anchor":"event_date","sched_status_ids":[],"sched_event_type_ids":[],"schedule_from":"master_admin","sched_send_to":["primary_client"],"review_reasons":[]},{"legacy_djep_id":217306,"name":"Excitement Builds for Your Event - Follow-up on Quote from Xpress Entertainment","display_name":"Quote Sent - Reminder 2","group_name":"QUOTE","subject":"","body_html":"<html>\r\n<head>\r\n\t<title></title>\r\n</head>\r\n<body data-gr-ext-installed=\"\" data-new-gr-c-s-check-loaded=\"14.1121.0\">\r\n<p>Hey&nbsp;<first_name>,<br />\r\n\t<br />\r\n\tI hope you&#39;re doing well and full of anticipation for your upcoming <event_type>. It has been a week since we sent you the quote, and we are absolutely thrilled to reconnect with you. The idea of being part of your special day has us eagerly awaiting your response.<br />\r\n\t<br />\r\n\tWe understand that event planning can involve careful consideration, and we want to assure you that we are here to address any questions or concerns you may have. Our goal is to offer you a comprehensive understanding of the quote and tailor our services to meet your specific requirements. We are more than willing to make adjustments, add enhancements, or provide further information to ensure your complete satisfaction.<br />\r\n\t<br />\r\n\tOnce again, we would like to express our sincere gratitude for considering Xpress Entertainment for your event. ","is_active":true,"is_sms":false,"djep_was_enabled":true,"schedule_enabled":false,"schedule_days":7,"schedule_direction":"after","schedule_anchor":"event_date","sched_status_ids":["a68a9f16-ae52-4442-941a-cc7b9ceed711"],"sched_event_type_ids":[],"schedule_from":"salesperson","sched_send_to":["primary_client"],"review_reasons":["Imported timing anchor “Custom Event Date 2” has no XOS equivalent — pick a send trigger before enabling."]},{"legacy_djep_id":217307,"name":"Follow-up on Your DJ and Entertainment Quote - Excitement Intensifies!","display_name":"Quote Sent - Reminder 3","group_name":"QUOTE","subject":"","body_html":"<html>\r\n<head>\r\n\t<title></title>\r\n</head>\r\n<body data-gr-ext-installed=\"\" data-new-gr-c-s-check-loaded=\"14.1121.0\">\r\n<p>Howdy <first_name>,<br />\r\n\t<br />\r\n\tI hope this email finds you well and that the planning for your upcoming event is progressing smoothly. It has been 12 days since we sent you the quote for hiring a DJ and entertainment, and we wanted to touch base with you as the excitement builds..<br />\r\n\t<br />\r\n\tWe understand that organizing an event involves meticulous details, and we want to ensure that you have all the information you need to make an informed decision. At Xpress Entertainment, we are passionate about delivering exceptional DJ and entertainment services that create a vibrant and unforgettable experience for your guests.<br />\r\n\t<br />\r\n\tWe genuinely appreciate your interest in Xpress Entertainment and the opportunity to be a part of your event. We want to assure you that your satisfaction is our utmost priority, and we are here to address any questions, conc","is_active":true,"is_sms":false,"djep_was_enabled":true,"schedule_enabled":false,"schedule_days":12,"schedule_direction":"after","schedule_anchor":"event_date","sched_status_ids":["a68a9f16-ae52-4442-941a-cc7b9ceed711"],"sched_event_type_ids":[],"schedule_from":"salesperson","sched_send_to":["primary_client"],"review_reasons":["Imported timing anchor “Custom Event Date 2” has no XOS equivalent — pick a send trigger before enabling."]},{"legacy_djep_id":217310,"name":"Just Checking,","display_name":"1 - Agreement Reminder","group_name":"BOOKING AGREEMENT","subject":"","body_html":"<html>\r\n<head>\r\n\t<title></title>\r\n</head>\r\n<body data-gr-ext-installed=\"\" data-new-gr-c-s-check-loaded=\"14.1112.0\">Hey <first_name>, just making sure that the contract made it to you.<br />\r\n<br />\r\nFeel free to contact me with any questions, thanks!<br />\r\n<company_email_signature></body>\r\n</html>\r\n","is_active":true,"is_sms":false,"djep_was_enabled":true,"schedule_enabled":false,"schedule_days":1,"schedule_direction":"after","schedule_anchor":"contract_sent_date","sched_status_ids":["c0c9d5e3-2703-4a33-8c71-90c43d228249"],"sched_event_type_ids":[],"schedule_from":"master_admin","sched_send_to":["primary_client"],"review_reasons":[]},{"legacy_djep_id":217311,"name":"Your date will only be reserved for another week","display_name":"2 - Agreement Reminder","group_name":"BOOKING AGREEMENT","subject":"","body_html":"<html>\r\n<head>\r\n\t<title></title>\r\n</head>\r\n<body data-gr-ext-installed=\"\" data-new-gr-c-s-check-loaded=\"14.1112.0\">Hey <first_name>, Your date&nbsp;will only be reserved for&nbsp;another