fore","schedule_anchor":"event_date","sched_status_ids":["c0d3e855-ac0c-4a14-afdf-c00f7b5dbec5","5704490c-b089-4f5f-9756-0523c45b5daa"],"sched_event_type_ids":[],"schedule_from":"master_admin","sched_send_to":["primary_client"],"review_reasons":[]},{"legacy_djep_id":217439,"name":"Payment Link for Your Added Enhancements","display_name":"Additional Addons Email (With PayPal Payment Link)","group_name":"PAYMENTS","subject":"","body_html":"<html>\r\n<head>\r\n\t<title></title>\r\n</head>\r\n<body data-gr-ext-installed=\"\" data-new-gr-c-s-check-loaded=\"14.1271.0\" data-new-gr-c-s-loaded=\"14.1271.0\">\r\n<p>Hi <first_name>,<br />\r\n\t<br />\r\n\tSo excited to move forward with the additional enhancements you&rsquo;ve selected for your event! &#127881;Below is the secure payment link for the added services to your existing booking at <event_location>.<br />\r\n\t<br />\r\n\t&#128073; <strong>Total Cost:</strong>&nbsp;<custom_field4><br />\r\n\t<br />\r\n\t&#128073; <strong>Payment Link:</strong> <custom_field3><br />\r\n\t<br />\r\n\tPlease note: A 4% service fee has been included in this invoice. To avoid this fee, you may opt to pay via Zelle to office@xpressdjs.com.<br />\r\n\tIf you choose to pay via Zelle, send us a quick message once the payment has been sent so we can update your account accordingly.<br />\r\n\t<br />\r\n\tAs always, if you have any questions or want to make any final tweaks, don&rsquo;t hesitate to reach out. We can&rsquo;t wait to bring these ","is_active":true,"is_sms":false,"djep_was_enabled":false,"schedule_enabled":false,"schedule_days":0,"schedule_direction":"before","schedule_anchor":"event_date","sched_status_ids":[],"sched_event_type_ids":[],"schedule_from":"master_admin","sched_send_to":["primary_client"],"review_reasons":[]}]$DJEP_2026$::jsonb) as x(
  legacy_djep_id bigint, name text, display_name text, group_name text, subject text, body_html text,
  is_active boolean, is_sms boolean, djep_was_enabled boolean,
  schedule_enabled boolean, schedule_days int, schedule_direction text, schedule_anchor text,
  sched_status_ids text[], sched_event_type_ids text[], schedule_from text, sched_send_to text[], review_reasons text[])
on conflict (legacy_djep_id) do update set
  name=excluded.name, display_name=excluded.display_name, group_name=excluded.group_name,
  body_html=excluded.body_html, is_sms=excluded.is_sms, djep_was_enabled=excluded.djep_was_enabled,
  schedule_days=excluded.schedule_days, schedule_direction=excluded.schedule_direction,
  schedule_anchor=excluded.schedule_anchor, sched_status_ids=excluded.sched_status_ids,
  sched_event_type_ids=excluded.sched_event_type_ids, schedule_from=excluded.schedule_from,
  sched_send_to=excluded.sched_send_to, review_reasons=excluded.review_reasons;
